                                    {hasPurchase && <td style={{ padding: "5px 8px", fontSize: 9, color: "var(--color-text-tertiary)", maxWidth: 130, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{p.suppliers.length > 0 ? p.suppliers[0] : "—"}</td>}
